/* ============================================================
   Murmur — Open-Source Reliability Harness for Coding Agents
   Tech-Noir Palette | CSS Variables | Responsive 320–1200px
   ============================================================ */

/* ----- CSS Custom Properties ----- */
:root {
    --bg: #e4e4e0;
    --bg-surface: #ecece8;
    --bg-card: #f2f2ef;
    --accent: #e8192a;
    --accent-hover: #c41524;
    --accent-glow: rgba(232, 25, 42, 0.08);
    --text: #1a1a1a;
    --text-muted: #5c5c57;
    --text-inverse: #f8f8f6;
    --border: rgba(0, 0, 0, 0.10);
    --border-strong: rgba(0, 0, 0, 0.18);
    --dark: #111110;
    --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06);
    --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.08);
    --radius: 6px;
    --radius-lg: 10px;
    --font-mono: 'SF Mono', 'Cascadia Code', 'Consolas', 'Menlo', monospace;
    --font-sans: 'Inter', 'SF Pro', 'Segoe UI', system-ui, -apple-system, sans-serif;
    --letter-spacing-heading: 0.04em;
    --container-max: 1100px;
    --transition: 180ms ease;
}

/* ----- Reset & Base ----- */
*,
*::before,
*::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

html {
    scroll-behavior: smooth;
    -webkit-text-size-adjust: 100%;
}

body {
    font-family: var(--font-sans);
    background-color: var(--bg);
    color: var(--text);
    line-height: 1.6;
    font-size: 16px;
    min-width: 320px;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
    transition: color var(--transition);
}

/* ----- Container ----- */
.container {
    width: 100%;
    max-width: var(--container-max);
    margin: 0 auto;
    padding: 0 20px;
}

@media (min-width: 768px) {
    .container {
        padding: 0 32px;
    }
}

@media (min-width: 1100px) {
    .container {
        padding: 0 40px;
    }
}

/* ----- Screen Reader Only ----- */
.sr-only {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
}

/* ============================================================
   HEADER
   ============================================================ */
.site-header {
    border-bottom: 1px solid var(--border);
    background-color: var(--bg);
    position: sticky;
    top: 0;
    z-index: 100;
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    background-color: rgba(228, 228, 224, 0.92);
}

.site-header .container {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 56px;
}

@media (min-width: 768px) {
    .site-header .container {
        height: 64px;
    }
}

.logo {
    display: flex;
    align-items: center;
    gap: 10px;
    font-weight: 700;
    font-size: 1.15rem;
    letter-spacing: var(--letter-spacing-heading);
    color: var(--dark);
}

.logo-mark {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 30px;
    height: 30px;
    background-color: var(--accent);
    color: var(--text-inverse);
    font-family: var(--font-mono);
    font-weight: 800;
    font-size: 0.85rem;
    border-radius: 4px;
    letter-spacing: 0;
}

.logo-text {
    text-transform: lowercase;
}

.nav-links {
    display: flex;
    align-items: center;
    gap: 20px;
    font-size: 0.9rem;
    font-weight: 500;
    color: var(--text-muted);
}

.nav-links a:hover {
    color: var(--accent);
}

@media (min-width: 768px) {
    .nav-links {
        gap: 28px;
        font-size: 0.95rem;
    }
}

/* ============================================================
   HERO
   ============================================================ */
.hero {
    padding: 48px 0 56px;
    text-align: center;
}

@media (min-width: 768px) {
    .hero {
        padding: 72px 0 80px;
    }
}

@media (min-width: 1024px) {
    .hero {
        padding: 96px 0 104px;
    }
}

.hero-headline {
    font-size: 2rem;
    font-weight: 800;
    line-height: 1.2;
    letter-spacing: var(--letter-spacing-heading);
    color: var(--dark);
    max-width: 700px;
    margin: 0 auto 20px;
    text-wrap: balance;
}

.hero-headline .accent {
    color: var(--accent);
    position: relative;
}

.hero-headline .accent::after {
    content: '';
    position: absolute;
    bottom: 2px;
    left: 0;
    width: 100%;
    height: 4px;
    background-color: var(--accent);
    opacity: 0.2;
    border-radius: 2px;
}

@media (min-width: 600px) {
    .hero-headline {
        font-size: 2.5rem;
    }
}

@media (min-width: 768px) {
    .hero-headline {
        font-size: 3rem;
    }
}

@media (min-width: 1024px) {
    .hero-headline {
        font-size: 3.4rem;
    }
}

.hero-subhead {
    font-size: 1rem;
    color: var(--text-muted);
    max-width: 580px;
    margin: 0 auto 32px;
    line-height: 1.7;
    text-wrap: balance;
}

@media (min-width: 768px) {
    .hero-subhead {
        font-size: 1.1rem;
    }
}

.hero-actions {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 12px;
}

@media (min-width: 480px) {
    .hero-actions {
        flex-direction: row;
        justify-content: center;
        gap: 16px;
    }
}

/* ----- Buttons ----- */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 12px 28px;
    font-size: 0.95rem;
    font-weight: 600;
    border-radius: var(--radius);
    letter-spacing: 0.02em;
    cursor: pointer;
    transition: all var(--transition);
    border: 1.5px solid transparent;
    white-space: nowrap;
}

.btn-primary {
    background-color: var(--accent);
    color: var(--text-inverse);
    border-color: var(--accent);
}

.btn-primary:hover {
    background-color: var(--accent-hover);
    border-color: var(--accent-hover);
    box-shadow: 0 0 0 4px var(--accent-glow);
}

.btn-secondary {
    background-color: transparent;
    color: var(--dark);
    border-color: var(--border-strong);
}

.btn-secondary:hover {
    border-color: var(--dark);
    background-color: rgba(0, 0, 0, 0.03);
}

/* ============================================================
   METRICS STRIP
   ============================================================ */
.metrics-strip {
    background-color: var(--dark);
    color: var(--text-inverse);
    padding: 36px 0;
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
}

.metrics-strip .container {
    display: flex;
    flex-direction: column;
    gap: 28px;
    align-items: center;
    text-align: center;
}

@media (min-width: 600px) {
    .metrics-strip .container {
        flex-direction: row;
        justify-content: space-around;
        gap: 16px;
        text-align: center;
    }
}

@media (min-width: 768px) {
    .metrics-strip {
        padding: 48px 0;
    }
    .metrics-strip .container {
        justify-content: space-between;
        text-align: left;
    }
}

.metric-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
}

@media (min-width: 768px) {
    .metric-item {
        align-items: flex-start;
    }
}

.metric-value {
    font-family: var(--font-mono);
    font-size: 2.4rem;
    font-weight: 800;
    letter-spacing: 0.02em;
    color: #fff;
    line-height: 1.1;
}

@media (min-width: 768px) {
    .metric-value {
        font-size: 2.8rem;
    }
}

.metric-label {
    font-family: var(--font-mono);
    font-size: 0.8rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: var(--accent);
    margin-top: 4px;
}

.metric-desc {
    font-size: 0.8rem;
    color: rgba(248, 248, 246, 0.6);
    margin-top: 4px;
    max-width: 200px;
    line-height: 1.4;
}

/* ============================================================
   FEATURES
   ============================================================ */
.features {
    padding: 56px 0 64px;
}

@media (min-width: 768px) {
    .features {
        padding: 80px 0 88px;
    }
}

.section-heading {
    font-size: 1.6rem;
    font-weight: 800;
    letter-spacing: var(--letter-spacing-heading);
    color: var(--dark);
    text-align: center;
    margin-bottom: 8px;
}

@media (min-width: 768px) {
    .section-heading {
        font-size: 2rem;
    }
}

.section-subhead {
    text-align: center;
    color: var(--text-muted);
    font-size: 0.95rem;
    max-width: 500px;
    margin: 0 auto 40px;
    line-height: 1.6;
}

@media (min-width: 768px) {
    .section-subhead {
        font-size: 1rem;
        margin-bottom: 52px;
    }
}

.cards-grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: 20px;
}

@media (min-width: 600px) {
    .cards-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (min-width: 900px) {
    .cards-grid {
        grid-template-columns: repeat(3, 1fr);
        gap: 24px;
    }
}

.feature-card {
    background-color: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 28px 24px;
    transition: box-shadow var(--transition), border-color var(--transition);
}

.feature-card:hover {
    box-shadow: var(--shadow-md);
    border-color: var(--border-strong);
}

.card-icon {
    font-size: 1.8rem;
    color: var(--accent);
    margin-bottom: 12px;
    line-height: 1;
}

.card-title {
    font-size: 1.1rem;
    font-weight: 700;
    letter-spacing: var(--letter-spacing-heading);
    color: var(--dark);
    margin-bottom: 8px;
}

.card-desc {
    font-size: 0.9rem;
    color: var(--text-muted);
    line-height: 1.7;
}

/* ============================================================
   TESTIMONIAL
   ============================================================ */
.testimonial {
    padding: 48px 0 56px;
    border-top: 1px solid var(--border);
    background-color: var(--bg-surface);
}

@media (min-width: 768px) {
    .testimonial {
        padding: 64px 0 72px;
    }
}

.testimonial-quote {
    max-width: 700px;
    margin: 0 auto;
    text-align: center;
    position: relative;
}

.testimonial-quote::before {
    content: '\201C';
    display: block;
    font-size: 4rem;
    line-height: 1;
    color: var(--accent);
    font-family: Georgia, 'Times New Roman', serif;
    margin-bottom: -12px;
    opacity: 0.7;
}

.testimonial-quote p {
    font-size: 1.05rem;
    line-height: 1.75;
    color: var(--text);
    font-style: italic;
    text-wrap: balance;
}

@media (min-width: 768px) {
    .testimonial-quote p {
        font-size: 1.2rem;
    }
}

.testimonial-attribution {
    margin-top: 20px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
}

.testimonial-attribution cite {
    font-style: normal;
    font-weight: 700;
    font-size: 0.95rem;
    color: var(--dark);
    letter-spacing: 0.02em;
}

.testimonial-role {
    font-size: 0.8rem;
    color: var(--text-muted);
    font-style: normal;
}

/* ============================================================
   FOOTER
   ============================================================ */
.site-footer {
    background-color: var(--dark);
    color: rgba(248, 248, 246, 0.7);
    padding: 40px 0 28px;
    font-size: 0.85rem;
}

.site-footer .container {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 20px;
    text-align: center;
}

@media (min-width: 600px) {
    .site-footer .container {
        flex-direction: row;
        flex-wrap: wrap;
        justify-content: space-between;
        text-align: left;
    }
}

.footer-brand .logo-text {
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
    letter-spacing: var(--letter-spacing-heading);
    display: block;
    margin-bottom: 4px;
}

.footer-tagline {
    color: rgba(248, 248, 246, 0.5);
    font-size: 0.8rem;
}

.footer-social {
    display: flex;
    gap: 18px;
    flex-wrap: wrap;
    justify-content: center;
}

.social-link {
    color: rgba(248, 248, 246, 0.6);
    font-weight: 500;
    font-size: 0.85rem;
    transition: color var(--transition);
}

.social-link:hover {
    color: var(--accent);
}

.footer-copy {
    color: rgba(248, 248, 246, 0.35);
    font-size: 0.75rem;
    width: 100%;
    text-align: center;
    margin-top: 8px;
}

@media (min-width: 600px) {
    .footer-copy {
        text-align: left;
        margin-top: 4px;
    }
}

/* ============================================================
   UTILITY: Focus styles for accessibility
   ============================================================ */
a:focus-visible,
.btn:focus-visible {
    outline: 2px solid var(--accent);
    outline-offset: 2px;
}

/* ============================================================
   RESPONSIVE FINE-TUNING
   ============================================================ */
@media (max-width: 359px) {
    .hero-headline {
        font-size: 1.55rem;
    }

    .metric-value {
        font-size: 1.8rem;
    }

    .nav-links {
        gap: 12px;
        font-size: 0.8rem;
    }

    .btn {
        padding: 10px 20px;
        font-size: 0.85rem;
    }
}

@media (min-width: 1200px) {
    .hero-headline {
        font-size: 3.6rem;
        max-width: 800px;
    }

    .hero-subhead {
        max-width: 640px;
    }
}

