}

.feature-card:hover {
    box-shadow: var(--shadow-md);
    border-color: var(--border-strong);
}

.card-icon {
    font-size: 1.8rem;
    color: var(--accent);
    margin-bottom: 12px;
    line-height: 1;
}

.card-title {
