    }
}

.testimonial-quote {
    max-width: 700px;
    margin: 0 auto;
    text-align: center;
    position: relative;
}

.testimonial-quote::before {
    content: '\201C';
    display: block;
    font-size: 4rem;
    line-height: 1;
    color: var(--accent);
    font-family: Georgia, 'Times New Roman', serif;
    margin-bottom: -12px;
    opacity: 0.7;
}

.testimonial-quote p {
    font-size: 1.05rem;
    line-height: 1.75;
    color: var(--text);
    font-style: italic;
    text-wrap: balance;
}

@media (min-width: 768px) {
    .testimonial-quote p {
        font-size: 1.2rem;
    }
}

.testimonial-attribution {
    margin-top: 20px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
}

.testimonial-attribution cite {
    font-style: normal;
    font-weight: 700;
    font-size: 0.95rem;
    color: var(--dark);
    letter-spacing: 0.02em;
}

.testimonial-role {
    font-size: 0.8rem;
    color: var(--text-muted);
    font-style: normal;
}

/* ============================================================
   FOOTER
   ============================================================ */
.site-footer {
    background-color: var(--dark);
    color: rgba(248, 248, 246, 0.7);
    padding: 40px 0 28px;
    font-size: 0.85rem;
}

.site-footer .container {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 20px;
    text-align: center;
}

@media (min-width: 600px) {
    .site-footer .container {
        flex-direction: row;
        flex-wrap: wrap;
        justify-content: space-between;
        text-align: left;
    }
}

.footer-brand .logo-text {
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
    letter-spacing: var(--letter-spacing-heading);
