    margin-bottom: 4px;
}

.footer-tagline {
    color: rgba(248, 248, 246, 0.5);
    font-size: 0.8rem;
}

.footer-social {
    display: flex;
    gap: 18px;
    flex-wrap: wrap;
    justify-content: center;
}

.social-link {
    color: rgba(248, 248, 246, 0.6);
    font-weight: 500;
    font-size: 0.85rem;
    transition: color var(--transition);
}

.social-link:hover {
    color: var(--accent);
}

.footer-copy {
    color: rgba(248, 248, 246, 0.35);
    font-size: 0.75rem;
    width: 100%;
    text-align: center;
    margin-top: 8px;
}

@media (min-width: 600px) {
    .footer-copy {
        text-align: left;
        margin-top: 4px;
    }
}

/* ============================================================
   UTILITY: Focus styles for accessibility
   ============================================================ */
a:focus-visible,
.btn:focus-visible {
    outline: 2px solid var(--accent);
    outline-offset: 2px;
}

/* ============================================================
   RESPONSIVE FINE-TUNING
   ============================================================ */
@media (max-width: 359px) {
    .hero-headline {
        font-size: 1.55rem;
    }

    .metric-value {
        font-size: 1.8rem;
    }

    .nav-links {
        gap: 12px;
        font-size: 0.8rem;
    }

    .btn {
        padding: 10px 20px;
        font-size: 0.85rem;
    }
}

@media (min-width: 1200px) {
    .hero-headline {
        font-size: 3.6rem;
        max-width: 800px;
    }

    .hero-subhead {
        max-width: 640px;
    }
}

