/* ============================================================
   Murmur — Open-Source Reliability Harness for Coding Agents
   Tech-Noir Palette | CSS Variables | Responsive 320–1200px
   ============================================================ */

/* ----- CSS Custom Properties ----- */
:root {
    --bg: #e4e4e0;
    --bg-surface: #ecece8;
    --bg-card: #f2f2ef;
    --accent: #e8192a;
    --accent-hover: #c41524;
    --accent-glow: rgba(232, 25, 42, 0.08);
    --text: #1a1a1a;
    --text-muted: #5c5c57;
    --text-inverse: #f8f8f6;
    --border: rgba(0, 0, 0, 0.10);
    --border-strong: rgba(0, 0, 0, 0.18);
    --dark: #111110;
    --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06);
    --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.08);
    --radius: 6px;
    --radius-lg: 10px;
    --font-mono: 'SF Mono', 'Cascadia Code', 'Consolas', 'Menlo', monospace;
    --font-sans: 'Inter', 'SF Pro', 'Segoe UI', system-ui, -apple-system, sans-serif;
    --letter-spacing-heading: 0.04em;
    --container-max: 1100px;
    --transition: 180ms ease;
}

/* ----- Reset & Base ----- */
*,
*::before,
*::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

html {
    scroll-behavior: smooth;
    -webkit-text-size-adjust: 100%;
}

body {
    font-family: var(--font-sans);
    background-color: var(--bg);
    color: var(--text);
    line-height: 1.6;
    font-size: 16px;
    min-width: 320px;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
    transition: color var(--transition);
}

/* ----- Container ----- */
.container {
    width: 100%;
    max-width: var(--container-max);
    margin: 0 auto;
    padding: 0 20px;
}

@media (min-width: 768px) {
    .container {
        padding: 0 32px;
    }
}

@media (min-width: 1100px) {
    .container {
        padding: 0 40px;
    }
}

/* ----- Screen Reader Only ----- */
.sr-only {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
}

/* ============================================================
   HEADER
   ============================================================ */
.site-header {
    border-bottom: 1px solid var(--border);
    background-color: var(--bg);
    position: sticky;
    top: 0;
    z-index: 100;
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    background-color: rgba(228, 228, 224, 0.92);
}

.site-header .container {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 56px;
}

@media (min-width: 768px) {
    .site-header .container {
        height: 64px;
    }
}

.logo {
    display: flex;
    align-items: center;
    gap: 10px;
    font-weight: 700;
    font-size: 1.15rem;
    letter-spacing: var(--letter-spacing-heading);
    color: var(--dark);
}

.logo-mark {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 30px;
    height: 30px;
    background-color: var(--accent);
    color: var(--text-inverse);
    font-family: var(--font-mono);
    font-weight: 800;
    font-size: 0.85rem;
    border-radius: 4px;
    letter-spacing: 0;
}

.logo-text {
    text-transform: lowercase;
}

.nav-links {
    display: flex;
    align-items: center;
    gap: 20px;
