    .hero-title {
        letter-spacing: 0.14em;
    }

    .testimonial blockquote {
        font-size: 1.5rem;
        padding: var(--spacing-lg);
    }
}

/* ==========================================================================
   Large screens (min‑width: 1200px)
   ========================================================================== */
@media screen and (min-width: 1200px) {
    .hero {
        padding: var(--spacing-xl) 0 var(--spacing-lg);
    }

    .container {
        padding-left: 0;
        padding-right: 0;
    }
}

