args.content:
/* ============================================================
   Murmur — Reliability Harness for Coding Agents
   Tech-Noir Palette • CSS-Only • 320px–1200px Responsive
   ============================================================ */

/* ----- CSS Custom Properties ----- */
:root {
  --color-bg: #e4e4e0;
  --color-surface: #f4f4ef;
  --color-surface-alt: #ecece6;
  --color-accent: #e8192a;
  --color-accent-glow: rgba(232, 25, 42, 0.12);
  --color-text: #141413;
  --color-text-secondary: #5a5954;
  --color-text-tertiary: #8a8982;
  --color-border: #cdccc5;
  --color-border-light: #d9d8d2;
  --color-code-bg: #1e1e1c;
  --color-code-text: #d4d4cf;
  --color-code-comment: #6e6d68;
  --color-code-pass: #3cb371;
  --color-code-warn: #e8a819;
  --color-code-dim: #7a7974;

  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --font-mono: 'JetBrains Mono', 'SF Mono', 'Fira Code', 'Cascadia Code', monospace;

  --spacing-xs: 0.375rem;
  --spacing-sm: 0.75rem;
  --spacing-md: 1.25rem;
  --spacing-lg: 2rem;
  --spacing-xl: 3rem;
  --spacing-2xl: 5rem;

  --border-thin: 1px solid var(--color-border);
  --border-accent: 1px solid var(--color-accent);

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 14px;

  --letter-spacing-heading: 0.04em;
  --letter-spacing-wide: 0.08em;

  --max-width: 1140px;
  --max-width-narrow: 820px;

  --shadow-card: 0 1px 3px rgba(0, 0, 0, 0.06), 0 1px 2px rgba(0, 0, 0, 0.04);
  --shadow-elevated: 0 4px 16px rgba(0, 0, 0, 0.08), 0 2px 6px rgba(0, 0, 0, 0.04);
}

/* ----- Reset & Base ----- */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-sans);
  background-color: var(--color-bg);
  color: var(--color-text);
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: var(--color-accent);
  text-decoration: none;
  transition: color 0.2s ease, background-color 0.2s ease;
}
a:hover {
  color: #c01020;
  text-decoration: underline;
}

ul {
  list-style: none;
}

code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--color-surface-alt);
  padding: 0.15em 0.4em;
  border-radius: 3px;
  border: var(--border-thin);
}

/* ----- Site Header / Navigation ----- */
.site-header {
  border-bottom: var(--border-thin);
  background: var(--color-bg);
  position: sticky;
  top: 0;
  z-index: 100;
}

.nav-bar {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: var(--spacing-sm) var(--spacing-md);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-md);
}

.nav-logo {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  text-decoration: none;
  color: var(--color-text);
  font-weight: 600;
  font-size: 1.15rem;
  letter-spacing: var(--letter-spacing-wide);
  text-transform: uppercase;
}
.nav-logo:hover {
  color: var(--color-accent);
  text-decoration: none;
}

.logo-mark {
  font-size: 1.3rem;
  color: var(--color-accent);
  line-height: 1;
}

.logo-text {
  letter-spacing: var(--letter-spacing-wide);
}

.nav-links {
  display: flex;
  gap: var(--spacing-lg);
  align-items: center;
  flex-wrap: wrap;
}

.nav-links a {
  color: var(--color-text-secondary);
  font-size: 0.9rem;
  font-weight: 500;
  letter-spacing: var(--letter-spacing-heading);
  text-decoration: none;
  padding: var(--spacing-xs) 0;
  border-bottom: 2px solid transparent;
  transition: border-color 0.2s ease, color 0.2s ease;
}
.nav-links a:hover {
  color: var(--color-accent);
  border-bottom-color: var(--color-accent);
  text-decoration: none;
}

/* ----- Hero ----- */
.hero {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: var(--spacing-2xl) var(--spacing-md);
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--spacing-xl);
  align-items: center;
}

.hero-content {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.hero-overline {
  font-family: var(--font-mono);
  font-size: 0.8rem;
  letter-spacing: var(--letter-spacing-wide);
  text-transform: uppercase;
  color: var(--color-text-tertiary);
}

.hero-headline {
  font-size: clamp(1.75rem, 4.5vw, 2.85rem);
  font-weight: 600;
  line-height: 1.2;
  letter-spacing: var(--letter-spacing-heading);
  color: var(--color-text);
}

.hero-emphasis {
  color: var(--color-accent);
  font-weight: 700;
}

.hero-subtitle {
  font-size: 1.05rem;
  color: var(--color-text-secondary);
  line-height: 1.7;
  max-width: 44ch;
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  margin-top: var(--spacing-xs);
}

/* ----- Buttons ----- */
.btn {
  display: inline-block;
  padding: 0.7em 1.5em;
  font-family: var(--font-sans);
  font-size: 0.9rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-heading);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all 0.2s ease;
  text-decoration: none;
  border: var(--border-thin);
}

.btn-primary {
  background: var(--color-accent);
  color: #fff;
  border-color: var(--color-accent);
}
.btn-primary:hover {
  background: #c01020;
  border-color: #c01020;
  color: #fff;
  text-decoration: none;
}

.btn-secondary {
  background: transparent;
  color: var(--color-text);
  border-color: var(--color-border);
}
.btn-secondary:hover {
  background: var(--color-surface);
  border-color: var(--color-text-secondary);
  color: var(--color-text);
  text-decoration: none;
}

.btn-large {
  padding: 0.85em 2.2em;
  font-size: 1rem;
}

/* ----- Hero Visual / Code Block ----- */
.hero-visual {
  background: var(--color-code-bg);
  border-radius: var(--radius-lg);
  padding: var(--spacing-md);
  border: var(--border-thin);
  border-color: #3a3a36;
  box-shadow: var(--shadow-elevated);
  overflow-x: auto;
}

.hero-code-block {
  margin: 0;
  font-family: var(--font-mono);
  font-size: 0.825rem;
  line-height: 1.7;
  color: var(--color-code-text);
  background: transparent;
  white-space: pre;
}

.code-comment { color: var(--color-code-comment); }
.code-prompt  { color: var(--color-accent); font-weight: 700; }
.code-dim     { color: var(--color-code-dim); }
.code-pass    { color: var(--color-code-pass); font-weight: 700; }
.code-stat    { color: #fff; font-weight: 700; }
.code-warn    { color: var(--color-code-warn); font-weight: 700; }
.code-stat-warn { color: var(--color-code-warn); font-weight: 700; }

/* ----- Metrics Strip ----- */
.metrics-strip {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: var(--spacing-2xl) var(--spacing-md);
  text-align: center;
}

.metrics-heading {
  font-size: 1.5rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-heading);
  margin-bottom: var(--spacing-xs);
  color: var(--color-text);
}

.metrics-subtitle {
  color: var(--color-text-secondary);
  font-size: 0.95rem;
  max-width: 52ch;
  margin: 0 auto var(--spacing-xl);
  line-height: 1.6;
}

.metrics-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--spacing-md);
}

.metric-card {
  background: var(--color-surface);
  border: var(--border-thin);
  border-radius: var(--radius-md);
  padding: var(--spacing-lg) var(--spacing-md);
  text-align: left;
  transition: box-shadow 0.25s ease, transform 0.25s ease;
}
.metric-card:hover {
  box-shadow: var(--shadow-elevated);
  transform: translateY(-2px);
  border-color: var(--color-accent);
}

.metric-label {
  display: block;
  font-family: var(--font-mono);
  font-size: 0.75rem;
  letter-spacing: var(--letter-spacing-wide);
  text-transform: uppercase;
  color: var(--color-text-tertiary);
  margin-bottom: var(--spacing-xs);
}

.metric-value {
  display: block;
  font-family: var(--font-mono);
  font-size: 2.4rem;
  font-weight: 700;
  color: var(--color-accent);
  line-height: 1.1;
  margin-bottom: var(--spacing-sm);
  letter-spacing: -0.02em;
}

.metric-detail {
  font-size: 0.875rem;
  color: var(--color-text-secondary);
  line-height: 1.6;
}

/* ----- Features ----- */
.features {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: var(--spacing-2xl) var(--spacing-md);
  text-align: center;
}

.features-heading {
  font-size: 1.5rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-heading);
  margin-bottom: var(--spacing-xs);
  color: var(--color-text);
}

.features-subtitle {
  color: var(--color-text-secondary);
  font-size: 0.95rem;
  max-width: 50ch;
  margin: 0 auto var(--spacing-xl);
  line-height: 1.6;
}

.features-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--spacing-lg);
  text-align: left;
}

.feature-card {
  background: var(--color-surface);
  border: var(--border-thin);
  border-radius: var(--radius-md);
  padding: var(--spacing-lg);
  transition: box-shadow 0.25s ease, border-color 0.25s ease;
}
.feature-card:hover {
  box-shadow: var(--shadow-elevated);
  border-color: var(--color-border);
}

.feature-icon {
  font-size: 1.6rem;
  margin-bottom: var(--spacing-sm);
  color: var(--color-accent);
}

.feature-title {
  font-size: 1.1rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-heading);
  margin-bottom: var(--spacing-sm);
  color: var(--color-text);
}

.feature-desc {
  font-size: 0.9rem;
  color: var(--color-text-secondary);
  line-height: 1.65;
}

/* ----- Testimonial ----- */
.testimonial {
  max-width: var(--max-width-narrow);
  margin: 0 auto;
  padding: var(--spacing-2xl) var(--spacing-md);
  text-align: center;
  border-top: var(--border-thin);
  border-bottom: var(--border-thin);
}

.testimonial-quote {
  font-size: 1.25rem;
  line-height: 1.7;
  color: var(--color-text);
  font-style: italic;
  letter-spacing: 0.01em;
  margin-bottom: var(--spacing-md);
  position: relative;
}
.testimonial-quote::before {
  content: '“';
  font-size: 3.5rem;
  color: var(--color-accent);
  opacity: 0.25;
  position: absolute;
  top: -1.2rem;
  left: -1rem;
  font-style: normal;
  line-height: 1;
  font-family: Georgia, serif;
}

.testimonial-attribution {
  display: flex;
  flex-direction: column;
  gap: 2px;
  font-style: normal;
}

.testimonial-name {
  font-weight: 600;
  font-size: 0.95rem;
  letter-spacing: var(--letter-spacing-heading);
  color: var(--color-text);
}

.testimonial-role {
  font-size: 0.8rem;
  color: var(--color-text-tertiary);
  letter-spacing: var(--letter-spacing-heading);
}

/* ----- CTA Banner ----- */
.cta-banner {
  max-width: var(--max-width-narrow);
  margin: 0 auto;
  padding: var(--spacing-2xl) var(--spacing-md);
  text-align: center;
}

.cta-heading {
  font-size: 1.35rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-heading);
  margin-bottom: var(--spacing-sm);
  color: var(--color-text);
}

.cta-subtitle {
  font-family: var(--font-mono);
  font-size: 0.85rem;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-lg);
}

/* ----- Footer ----- */
.site-footer {
  border-top: var(--border-thin);
  background: var(--color-surface-alt);
  padding: var(--spacing-2xl) var(--spacing-md) var(--spacing-lg);
  margin-top: auto;
}

.footer-grid {
  max-width: var(--max-width);
  margin: 0 auto;
  display: grid;
  grid-template-columns: 1.5fr 1fr 1fr 1fr;
  gap: var(--spacing-xl);
  padding-bottom: var(--spacing-xl);
  border-bottom: var(--border-thin);
}

.footer-brand {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
}

.footer-brand .logo-mark {
  font-size: 1.1rem;
}

.footer-brand .logo-text {
  font-size: 1rem;
  font-weight: 600;
}

.footer-tagline {
  font-size: 0.8rem;
  color: var(--color-text-tertiary);
  margin-top: var(--spacing-xs);
  line-height: 1.5;
}

.footer-heading {
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-wide);
  text-transform: uppercase;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);
}

.footer-links ul {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
}

.footer-links a {
  font-size: 0.85rem;
  color: var(--color-text-secondary);
  text-decoration: none;
}
.footer-links a:hover {
  color: var(--color-accent);
  text-decoration: underline;
}

.footer-bottom {
  max-width: var(--max-width);
  margin: 0 auto;
  padding-top: var(--spacing-md);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  font-size: 0.8rem;
  color: var(--color-text-tertiary);
}

.footer-social {
  display: flex;
  gap: var(--spacing-sm);
}

.footer-social a {
  font-size: 1rem;
  color: var(--color-text-tertiary);
  text-decoration: none;
  transition: color 0.2s ease;
}
.footer-social a:hover {
  color: var(--color-accent);
  text-decoration: none;
}

/* ============================================================
   RESPONSIVE BREAKPOINTS
   ============================================================ */

/* Tablet — under 900px */
@media (max-width: 900px) {
  .hero {
    grid-template-columns: 1fr;
    gap: var(--spacing-lg);
    padding-top: var(--spacing-xl);
    padding-bottom: var(--spacing-xl);
  }

  .hero-visual {
    order: -1;
  }

  .hero-code-block {
    font-size: 0.75rem;
  }

  .metrics-grid,
  .features-grid {
    grid-template-columns: 1fr;
    gap: var(--spacing-md);
  }

  .footer-grid {
    grid-template-columns: 1fr 1fr;
    gap: var(--spacing-lg);
  }

  .footer-brand {
    grid-column: 1 / -1;
  }

  .nav-links {
    gap: var(--spacing-md);
  }
}

/* Mobile — under 600px */
@media (max-width: 600px) {
  .nav-bar {
    flex-direction: column;
    gap: var(--spacing-sm);
    padding: var(--spacing-sm);
  }

  .nav-links {
    gap: var(--spacing-sm);
    justify-content: center;
  }

  .nav-links a {
    font-size: 0.8rem;
  }

  .hero {
    padding: var(--spacing-xl) var(--spacing-sm);
    gap: var(--spacing-md);
  }

  .hero-headline {
    font-size: 1.5rem;
  }

  .hero-subtitle {
    font-size: 0.9rem;
  }

  .hero-code-block {
    font-size: 0.65rem;
  }

  .hero-actions {
    flex-direction: column;
  }

  .btn {
    text-align: center;
  }

  .metrics-strip,
  .features,
  .cta-banner {
    padding: var(--spacing-xl) var(--spacing-sm);
  }

  .metrics-heading,
  .features-heading {
    font-size: 1.25rem;
  }

  .metric-value {
    font-size: 1.8rem;
  }

  .features-grid {
    gap: var(--spacing-md);
  }

  .testimonial {
    padding: var(--spacing-xl) var(--spacing-sm);
  }

  .testimonial-quote {
    font-size: 1.05rem;
  }

  .testimonial-quote::before {
    font-size: 2.5rem;
    top: -0.8rem;
    left: -0.4rem;
  }

  .footer-grid {
    grid-template-columns: 1fr;
    gap: var(--spacing-lg);
  }

  .footer-bottom {
    flex-direction: column;
    text-align: center;
    gap: var(--spacing-sm);
  }

  .cta-heading {
    font-size: 1.15rem;
  }
}

/* Wide desktop refinements — above 1200px */
@media (min-width: 1200px) {
  .hero {
    gap: var(--spacing-2xl);
  }

  .hero-headline {
    font-size: 3rem;
  }

  .features-grid {
    gap: var(--spacing-xl);
  }
}

/* Very small screens — 320px floor */
@media (max-width: 380px) {
  .hero-headline {
    font-size: 1.3rem;
  }

  .hero-code-block {
    font-size: 0.55rem;
  }

  .metric-value {
    font-size: 1.5rem;
  }

  .btn {
    padding: 0.6em 1em;
    font-size: 0.8rem;
  }

  .nav-links {
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--spacing-xs) var(--spacing-sm);
  }
}

