/* ----- CSS Custom Properties ----- */
:root {
  --color-bg: #e4e4e0;
  --color-surface: #f4f4ef;
  --color-surface-alt: #ecece6;
  --color-accent: #e8192a;
  --color-accent-glow: rgba(232, 25, 42, 0.12);
  --color-text: #141413;
  --color-text-secondary: #5a5954;
  --color-text-tertiary: #8a8982;
  --color-border: #cdccc5;
  --color-border-light: #d9d8d2;
  --color-code-bg: #1e1e1c;
  --color-code-text: #d4d4cf;
  --color-code-comment: #6e6d68;
  --color-code-pass: #3cb371;
  --color-code-warn: #e8a819;
  --color-code-dim: #7a7974;

  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --font-mono: 'JetBrains Mono', 'SF Mono', 'Fira Code', 'Cascadia Code', monospace;

  --spacing-xs: 0.375rem;
  --spacing-sm: 0.75rem;
  --spacing-md: 1.25rem;
  --spacing-lg: 2rem;
  --spacing-xl: 3rem;
  --spacing-2xl: 5rem;

  --border-thin: 1px solid var(--color-border);
  --border-accent: 1px solid var(--color-accent);

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 14px;

  --letter-spacing-heading: 0.04em;
  --letter-spacing-wide: 0.08em;

  --max-width: 1140px;
  --max-width-narrow: 820px;

  --shadow-card: 0 1px 3px rgba(0, 0, 0, 0.06), 0 1px 2px rgba(0, 0, 0, 0.04);
  --shadow-elevated: 0 4px 16px rgba(0, 0, 0, 0.08), 0 2px 6px rgba(0, 0, 0, 0.04);
}

/* ----- Reset & Base ----- */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-sans);
  background-color: var(--color-bg);
  color: var(--color-text);
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: var(--color-accent);
  text-decoration: none;
  transition: color 0.2s ease, background-color 0.2s ease;
}
a:hover {
  color: #c01020;
  text-decoration: underline;
}

ul {
  list-style: none;
}

code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--color-surface-alt);
  padding: 0.15em 0.4em;
  border-radius: 3px;
  border: var(--border-thin);
}

/* ----- Site Header / Navigation ----- */
.site-header {
  border-bottom: var(--border-thin);
  background: var(--color-bg);
  position: sticky;
  top: 0;
  z-index: 100;
}

.nav-bar {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: var(--spacing-sm) var(--spacing-md);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-md);
}

.nav-logo {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  text-decoration: none;
  color: var(--color-text);
  font-weight: 600;
  font-size: 1.15rem;
  letter-spacing: var(--letter-spacing-wide);
  text-transform: uppercase;
}
.nav-logo:hover {
  color: var(--color-accent);
  text-decoration: none;
}

.logo-mark {
  font-size: 1.3rem;
  color: var(--color-accent);
  line-height: 1;
}

.logo-text {
  letter-spacing: var(--letter-spacing-wide);
}

.nav-links {
  display: flex;
  gap: var(--spacing-lg);
  align-items: center;
  flex-wrap: wrap;
}

.nav-links a {
  color: var(--color-text-secondary);
  font-size: 0.9rem;
  font-weight: 500;
  letter-spacing: var(--letter-spacing-heading);
  text-decoration: none;
  padding: var(--spacing-xs) 0;
  border-bottom: 2px solid transparent;
  transition: border-color 0.2s ease, color 0.2s ease;
}
.nav-links a:hover {
  color: var(--color-accent);
  border-bottom-color: var(--color-accent);
  text-decoration: none;
}

