}

.feature-title {
  font-size: 1.1rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-heading);
  margin-bottom: var(--spacing-sm);
  color: var(--color-text);
}

.feature-desc {
  font-size: 0.9rem;
  color: var(--color-text-secondary);
  line-height: 1.65;
}

/* ----- Testimonial ----- */
.testimonial {
  max-width: var(--max-width-narrow);
  margin: 0 auto;
  padding: var(--spacing-2xl) var(--spacing-md);
  text-align: center;
  border-top: var(--border-thin);
  border-bottom: var(--border-thin);
}

.testimonial-quote {
  font-size: 1.25rem;
  line-height: 1.7;
  color: var(--color-text);
  font-style: italic;
  letter-spacing: 0.01em;
  margin-bottom: var(--spacing-md);
  position: relative;
}
.testimonial-quote::before {
  content: '“';
  font-size: 3.5rem;
  color: var(--color-accent);
  opacity: 0.25;
  position: absolute;
  top: -1.2rem;
  left: -1rem;
  font-style: normal;
  line-height: 1;
  font-family: Georgia, serif;
}

.testimonial-attribution {
  display: flex;
  flex-direction: column;
  gap: 2px;
  font-style: normal;
}

.testimonial-name {
  font-weight: 600;
  font-size: 0.95rem;
  letter-spacing: var(--letter-spacing-heading);
  color: var(--color-text);
}

.testimonial-role {
  font-size: 0.8rem;
  color: var(--color-text-tertiary);
  letter-spacing: var(--letter-spacing-heading);
}

/* ----- CTA Banner ----- */
.cta-banner {
  max-width: var(--max-width-narrow);
  margin: 0 auto;
  padding: var(--spacing-2xl) var(--spacing-md);
  text-align: center;
}

.cta-heading {
  font-size: 1.35rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-heading);
  margin-bottom: var(--spacing-sm);
  color: var(--color-text);
}

.cta-subtitle {
  font-family: var(--font-mono);
  font-size: 0.85rem;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-lg);
}

/* ----- Footer ----- */
.site-footer {
  border-top: var(--border-thin);
  background: var(--color-surface-alt);
  padding: var(--spacing-2xl) var(--spacing-md) var(--spacing-lg);
  margin-top: auto;
}

.footer-grid {
  max-width: var(--max-width);
  margin: 0 auto;
  display: grid;
  grid-template-columns: 1.5fr 1fr 1fr 1fr;
  gap: var(--spacing-xl);
  padding-bottom: var(--spacing-xl);
  border-bottom: var(--border-thin);
}

.footer-brand {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
}

.footer-brand .logo-mark {
  font-size: 1.1rem;
}

.footer-brand .logo-text {
  font-size: 1rem;
  font-weight: 600;
}

.footer-tagline {
  font-size: 0.8rem;
  color: var(--color-text-tertiary);
  margin-top: var(--spacing-xs);
  line-height: 1.5;
}

.footer-heading {
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: var(--letter-spacing-wide);
  text-transform: uppercase;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);
}

.footer-links ul {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
}

.footer-links a {
  font-size: 0.85rem;
  color: var(--color-text-secondary);
  text-decoration: none;
}
.footer-links a:hover {
  color: var(--color-accent);
  text-decoration: underline;
}

.footer-bottom {
  max-width: var(--max-width);
  margin: 0 auto;
  padding-top: var(--spacing-md);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  font-size: 0.8rem;
  color: var(--color-text-tertiary);
}

.footer-social {
  display: flex;
  gap: var(--spacing-sm);
}

.footer-social a {
  font-size: 1rem;
  color: var(--color-text-tertiary);
  text-decoration: none;
  transition: color 0.2s ease;
}
.footer-social a:hover {
  color: var(--color-accent);
  text-decoration: none;
}

/* ============================================================
   RESPONSIVE BREAKPOINTS
   ============================================================ */

/* Tablet — under 900px */
@media (max-width: 900px) {
  .hero {
    grid-template-columns: 1fr;
    gap: var(--spacing-lg);
    padding-top: var(--spacing-xl);
    padding-bottom: var(--spacing-xl);
  }

  .hero-visual {
    order: -1;
  }

  .hero-code-block {
    font-size: 0.75rem;
  }

  .metrics-grid,
  .features-grid {
    grid-template-columns: 1fr;
    gap: var(--spacing-md);
  }

  .footer-grid {
    grid-template-columns: 1fr 1fr;
    gap: var(--spacing-lg);
  }

  .footer-brand {
    grid-column: 1 / -1;
  }

  .nav-links {
    gap: var(--spacing-md);
  }
}

/* Mobile — under 600px */
@media (max-width: 600px) {
  .nav-bar {
    flex-direction: column;
    gap: var(--spacing-sm);
    padding: var(--spacing-sm);
  }

  .nav-links {
    gap: var(--spacing-sm);
    justify-content: center;
  }

  .nav-links a {
    font-size: 0.8rem;
  }

  .hero {
    padding: var(--spacing-xl) var(--spacing-sm);
    gap: var(--spacing-md);
  }

  .hero-headline {
    font-size: 1.5rem;
  }

  .hero-subtitle {
    font-size: 0.9rem;
  }

  .hero-code-block {
    font-size: 0.65rem;
  }

  .hero-actions {
    flex-direction: column;
  }

  .btn {
    text-align: center;
  }

  .metrics-strip,
  .features,
  .cta-banner {
    padding: var(--spacing-xl) var(--spacing-sm);
  }

  .metrics-heading,
  .features-heading {
    font-size: 1.25rem;
  }

  .metric-value {
    font-size: 1.8rem;
  }

  .features-grid {
    gap: var(--spacing-md);
  }

  .testimonial {
    padding: var(--spacing-xl) var(--spacing-sm);
  }

  .testimonial-quote {
    font-size: 1.05rem;
  }

  .testimonial-quote::before {
    font-size: 2.5rem;
    top: -0.8rem;
    left: -0.4rem;
  }

  .footer-grid {
    grid-template-columns: 1fr;
    gap: var(--spacing-lg);
  }

  .footer-bottom {
    flex-direction: column;
    text-align: center;
    gap: var(--spacing-sm);
  }

  .cta-heading {
    font-size: 1.15rem;
  }
}

/* Wide desktop refinements — above 1200px */
@media (min-width: 1200px) {
  .hero {
    gap: var(--spacing-2xl);
  }

  .hero-headline {
    font-size: 3rem;
  }

  .features-grid {
    gap: var(--spacing-xl);
  }
}

/* Very small screens — 320px floor */
@media (max-width: 380px) {
  .hero-headline {
    font-size: 1.3rem;
  }

  .hero-code-block {
    font-size: 0.55rem;
  }

  .metric-value {
    font-size: 1.5rem;
  }

  .btn {
    padding: 0.6em 1em;
    font-size: 0.8rem;
  }

  .nav-links {
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--spacing-xs) var(--spacing-sm);
  }
}

