   MURMUR — TECH-NOIR STYLESHEET
   Palette: #e4e4e0 (bg), #e8192a (accent), thin borders,
   wide letter-spacing on headings.
   No frameworks. Responsive 320px → 1200px.
   ============================================================= */

/* ----- Custom Properties ----- */
:root {
  --color-bg: #e4e4e0;
  --color-surface: #dadad5;
