.testimonial figure {
  max-width: 680px;
  margin: 0 auto;
  text-align: center;
}

.testimonial blockquote {
  position: relative;
  padding-top: 1rem;
  margin-bottom: 1.5rem;
}

.testimonial blockquote::before {
  content: '\201C';
  display: block;
  font-family: var(--font-mono);
  font-size: 4rem;
  line-height: 1;
  color: var(--color-accent);
  opacity: 0.35;
