  border-top: var(--border-thin);
  padding-top: 1rem;
  font-size: 0.7rem;
  color: var(--color-muted);
  letter-spacing: 0.03em;
}

/* =============================================================
   RESPONSIVE BREAKPOINTS
   ============================================================= */

/* Below 768px — two-column grids, touch-friendly nav */
@media (max-width: 768px) {
  .metrics-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .features-grid {
    grid-template-columns: 1fr 1fr;
  }
}

/* Below 520px — full single-column */
@media (max-width: 520px) {
  .header-inner {
    flex-wrap: wrap;
    min-height: auto;
    padding-block: 0.75rem;
    gap: 0.5rem;
  }

  .nav {
    width: 100%;
    justify-content: flex-end;
    gap: 1rem;
    font-size: 0.78rem;
  }

  .hero-actions {
    flex-direction: column;
    align-items: center;
  }

  .btn-primary,
  .btn-secondary {
    width: 100%;
    max-width: 260px;
    text-align: center;
  }

  .metrics-grid {
    grid-template-columns: 1fr;
  }

  .features-grid {
    grid-template-columns: 1fr;
  }

  .footer-inner {
    flex-direction: column;
    gap: 1.25rem;
  }
}

/* Extremely narrow — 320px safe */
@media (max-width: 360px) {
  .nav {
    gap: 0.6rem;
    font-size: 0.7rem;
  }

  .logo-text {
    font-size: 0.95rem;
  }

  .hero-heading {
    font-size: 1.5rem;
  }
}

/* Wide — cap line length for readability */
@media (min-width: 1200px) {
  body {
    font-size: 1.05rem;
  }
}

