  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-sans);
  background-color: var(--color-bg);
  color: var(--color-text);
  line-height: 1.6;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

img,
svg {
  display: block;
  max-width: 100%;
}

a {
  color: inherit;
  text-decoration: none;
}

/* ----- Layout Utilities ----- */
.container {
  width: 100%;
  max-width: var(--max-width);
  margin-inline: auto;
  padding-inline: var(--gutter);
}

/* ----- HEADER ----- */
.site-header {
  border-bottom: var(--border-thin);
  position: sticky;
  top: 0;
  z-index: 100;
  background-color: var(--color-bg);
  backdrop-filter: blur(6px);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: 56px;
}

.logo {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-weight: 700;
  font-size: 1.1rem;
  letter-spacing: var(--ls-heading);
}

.nav {
  display: flex;
  align-items: center;
  gap: 1.5rem;
  font-size: 0.875rem;
  letter-spacing: var(--ls-heading);
  text-transform: lowercase;
}

.nav a:not(.nav-cta) {
  color: var(--color-muted);
  transition: color 0.15s;
}

.nav a:not(.nav-cta):hover {
  color: var(--color-text);
}

.nav-cta {
  border: var(--border-thin);
  padding: 0.35rem 0.9rem;
  border-radius: var(--radius);
  font-weight: 600;
  background: transparent;
  transition: background 0.2s, color 0.2s, border-color 0.2s;
}

.nav-cta:hover {
  background: var(--color-text);
  color: var(--color-bg);
  border-color: var(--color-text);
}

/* ----- HERO ----- */
.hero {
  padding: clamp(3rem, 8vw, 5.5rem) 0 clamp(2rem, 6vw, 4rem);
  text-align: center;
}

.hero-overline {
  display: inline-block;
  font-family: var(--font-mono);
  font-size: 0.7rem;
  letter-spacing: var(--ls-wide);
  text-transform: uppercase;
  color: var(--color-muted);
  border: var(--border-thin);
  padding: 0.25rem 0.75rem;
  border-radius: 99px;
  margin-bottom: 1.25rem;
}

.hero-heading {
  font-size: clamp(1.8rem, 5.5vw, 3.2rem);
  font-weight: 800;
  line-height: 1.12;
  letter-spacing: var(--ls-heading);
  max-width: 800px;
  margin: 0 auto 1rem;
}

.text-accent {
  color: var(--color-accent);
}

.hero-lead {
  font-size: clamp(1rem, 2.5vw, 1.15rem);
  color: var(--color-muted);
  max-width: 600px;
  margin: 0 auto 2rem;
  line-height: 1.55;
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  justify-content: center;
}

/* ----- Buttons ----- */
.btn-primary,
.btn-secondary {
  display: inline-block;
  padding: 0.65rem 1.5rem;
  font-size: 0.9rem;
  font-weight: 600;
  border-radius: var(--radius);
  letter-spacing: var(--ls-heading);
  transition: all 0.2s;
}

.btn-primary {
  background: var(--color-text);
  color: var(--color-bg);
  border: 1px solid var(--color-text);
}

.btn-primary:hover {
  background: var(--color-accent);
  border-color: var(--color-accent);
  color: #fff;
}

.btn-secondary {
  background: transparent;
  color: var(--color-text);
  border: var(--border-thin);
}

.btn-secondary:hover {
  border-color: var(--color-text);
  background: var(--color-card);
}

/* ----- METRICS ----- */
.metrics {
  background: var(--color-surface);
  border-top: var(--border-thin);
  border-bottom: var(--border-thin);
  padding: clamp(2rem, 5vw, 3rem) 0;
}

.metrics-heading {
  font-family: var(--font-mono);
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: var(--ls-wide);
  text-transform: uppercase;
  color: var(--color-muted);
  margin-bottom: 1.5rem;
}

.metrics-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--gutter);
}

.metric-card {
  background: var(--color-bg);
  border: var(--border-thin);
  padding: 1.25rem;
  border-radius: var(--radius);
}

.metric-label {
  display: block;
  font-family: var(--font-mono);
  font-size: 0.7rem;
  letter-spacing: var(--ls-wide);
  text-transform: uppercase;
  color: var(--color-muted);
  margin-bottom: 0.25rem;
}

.metric-label sup {
  font-size: 0.6rem;
}

.metric-value {
  display: block;
  font-family: var(--font-mono);
  font-size: clamp(2rem, 5vw, 2.8rem);
  font-weight: 700;
  color: var(--color-text);
  line-height: 1.1;
}

.metric-value small {
  font-size: 0.45em;
  color: var(--color-accent);
  margin-left: 0.15em;
}

.metric-desc {
  font-size: 0.8rem;
  color: var(--color-muted);
  margin-top: 0.5rem;
  line-height: 1.4;
}

.metrics-footnote {
  font-family: var(--font-mono);
  font-size: 0.65rem;
  color: var(--color-muted);
  margin-top: 1.25rem;
}

.metrics-footnote code {
  background: var(--color-bg);
  padding: 0.15em 0.4em;
  border-radius: 2px;
  border: var(--border-thin);
}

/* ----- FEATURES ----- */
.features {
  padding: clamp(3rem, 7vw, 5rem) 0;
}

.section-heading {
  font-size: clamp(1.5rem, 4vw, 2.2rem);
  font-weight: 800;
  letter-spacing: var(--ls-heading);
  text-align: center;
  margin-bottom: 0.5rem;
}

.section-sub {
  text-align: center;
  color: var(--color-muted);
  max-width: 520px;
  margin: 0 auto 2.5rem;
}

.features-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--gutter);
}

.feature-card {
  background: var(--color-card);
  border: var(--border-thin);
  padding: 1.75rem 1.5rem;
  border-radius: var(--radius);
  transition: border-color 0.2s, box-shadow 0.2s;
}

.feature-card:hover {
  border-color: var(--color-accent);
  box-shadow: 0 0 0 2px var(--color-accent-soft);
}

.feature-icon {
  margin-bottom: 1rem;
}

.feature-card h3 {
  font-size: 1.1rem;
  font-weight: 700;
  letter-spacing: var(--ls-heading);
  margin-bottom: 0.6rem;
}

.feature-card p {
  font-size: 0.9rem;
  color: var(--color-muted);
  line-height: 1.55;
}

/* ----- TESTIMONIAL ----- */
.testimonial {
  padding: clamp(2.5rem, 6vw, 4rem) 0 clamp(3rem, 7vw, 5rem);
  border-top: var(--border-thin);
}

.testimonial figure {
  max-width: 680px;
  margin: 0 auto;
  text-align: center;
}

.testimonial blockquote {
  position: relative;
  padding-top: 1rem;
  margin-bottom: 1.5rem;
}

.testimonial blockquote::before {
  content: '\201C';
  display: block;
  font-family: var(--font-mono);
  font-size: 4rem;
  line-height: 1;
  color: var(--color-accent);
  opacity: 0.35;
  margin-bottom: -1rem;
}

.testimonial blockquote p {
  font-size: clamp(1.05rem, 2.5vw, 1.25rem);
  font-style: italic;
  line-height: 1.6;
  color: var(--color-text);
}

.testimonial-name {
  display: block;
  font-weight: 700;
  letter-spacing: var(--ls-heading);
  margin-bottom: 0.2rem;
}

.testimonial-title {
  font-size: 0.8rem;
  color: var(--color-muted);
}

/* ----- FOOTER ----- */
.site-footer {
  border-top: var(--border-thin);
  padding: 2.25rem 0 1.25rem;
  background: var(--color-card);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  gap: 2rem;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: 1.5rem;
}

.footer-logo {
  font-weight: 700;
  font-size: 1rem;
  letter-spacing: var(--ls-heading);
  text-transform: lowercase;
}

.footer-tagline {
  font-size: 0.8rem;
  color: var(--color-muted);
  margin-top: 0.3rem;
  max-width: 240px;
}

.footer-social {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
}

.social-label {
  font-family: var(--font-mono);
  font-size: 0.65rem;
  letter-spacing: var(--ls-wide);
  text-transform: uppercase;
  color: var(--color-muted);
  margin-bottom: 0.2rem;
}

.footer-social a {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--color-muted);
  transition: color 0.15s;
}

.footer-social a:hover {
  color: var(--color-accent);
  text-decoration: underline;
  text-underline-offset: 3px;
}

.footer-bottom {
  border-top: var(--border-thin);
  padding-top: 1rem;
  font-size: 0.7rem;
  color: var(--color-muted);
  letter-spacing: 0.03em;
}

/* =============================================================
   RESPONSIVE BREAKPOINTS
   ============================================================= */

/* Below 768px — two‑column grids, touch‑friendly nav */
@media (max-width: 768px) {
  .metrics-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .features-grid {
    grid-template-columns: 1fr 1fr;
  }
}

/* Below 520px — full single‑column */
@media (max-width: 520px) {
  .header-inner {
    flex-wrap: wrap;
    min-height: auto;
    padding-block: 0.75rem;
    gap: 0.5rem;
  }

  .nav {
    width: 100%;
    justify-content: flex-end;
    gap: 1rem;
    font-size: 0.78rem;
  }

  .hero-actions {
    flex-direction: column;
    align-items: center;
  }

  .btn-primary,
  .btn-secondary {
    width: 100%;
    max-width: 260px;
    text-align: center;
  }

  .metrics-grid {
    grid-template-columns: 1fr;
  }

  .features-grid {
    grid-template-columns: 1fr;
  }

  .footer-inner {
    flex-direction: column;
    gap: 1.25rem;
  }
}

/* Extremely narrow — 320px safe */
@media (max-width: 360px) {
  .nav {
    gap: 0.6rem;
    font-size: 0.7rem;
  }

  .logo-text {
    font-size: 0.95rem;
  }

  .hero-heading {
    font-size: 1.5rem;
  }
}

/* Wide — cap line length for readability */
@media (min-width: 1200px) {
  body {
    font-size: 1.05rem;
  }
}

