.section-sub {
  text-align: center;
  color: var(--color-muted);
  max-width: 520px;
  margin: 0 auto 2.5rem;
}

.features-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--gutter);
}

.feature-card {
  background: var(--color-card);
  border: var(--border-thin);
  padding: 1.75rem 1.5rem;
  border-radius: var(--radius);
  transition: border-color 0.2s, box-shadow 0.2s;
}

.feature-card:hover {
  border-color: var(--color-accent);
  box-shadow: 0 0 0 2px var(--color-accent-soft);
}

.feature-icon {
  margin-bottom: 1rem;
}

.feature-card h3 {
  font-size: 1.1rem;
  font-weight: 700;
  letter-spacing: var(--ls-heading);
  margin-bottom: 0.6rem;
}

.feature-card p {
  font-size: 0.9rem;
  color: var(--color-muted);
  line-height: 1.55;
}

/* ----- TESTIMONIAL ----- */
.testimonial {
  padding: clamp(2.5rem, 6vw, 4rem) 0 clamp(3rem, 7vw, 5rem);
  border-top: var(--border-thin);
}

.testimonial figure {
  max-width: 680px;
  margin: 0 auto;
  text-align: center;
}

.testimonial blockquote {
  position: relative;
  padding-top: 1rem;
  margin-bottom: 1.5rem;
}

.testimonial blockquote::before {
  content: '\201C';
  display: block;
  font-family: var(--font-mono);
  font-size: 4rem;
  line-height: 1;
  color: var(--color-accent);
  opacity: 0.35;
  margin-bottom: -1rem;
}

.testimonial blockquote p {
  font-size: clamp(1.05rem, 2.5vw, 1.25rem);
  font-style: italic;
  line-height: 1.6;
  color: var(--color-text);
}

.testimonial-name {
  display: block;
  font-weight: 700;
  letter-spacing: var(--ls-heading);
  margin-bottom: 0.2rem;
}

.testimonial-title {
  font-size: 0.8rem;
  color: var(--color-muted);
}

/* ----- FOOTER ----- */
.site-footer {
  border-top: var(--border-thin);
  padding: 2.25rem 0 1.25rem;
  background: var(--color-card);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  gap: 2rem;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: 1.5rem;
}

.footer-logo {
  font-weight: 700;
  font-size: 1rem;
  letter-spacing: var(--ls-heading);
  text-transform: lowercase;
}

.footer-tagline {
  font-size: 0.8rem;
  color: var(--color-muted);
  margin-top: 0.3rem;
  max-width: 240px;
}

.footer-social {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
}

.social-label {
  font-family: var(--font-mono);
  font-size: 0.65rem;
  letter-spacing: var(--ls-wide);
  text-transform: uppercase;
  color: var(--color-muted);
  margin-bottom: 0.2rem;
}

.footer-social a {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--color-muted);
  transition: color 0.15s;
}

.footer-social a:hover {
  color: var(--color-accent);
  text-decoration: underline;
  text-underline-offset: 3px;
}

.footer-bottom {
  border-top: var(--border-thin);
  padding-top: 1rem;
  font-size: 0.7rem;
  color: var(--color-muted);
  letter-spacing: 0.03em;
}

/* =============================================================
   RESPONSIVE BREAKPOINTS
   ============================================================= */

/* Below 768px — two‑column grids, touch‑friendly nav */
@media (max-width: 768px) {
  .metrics-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .features-grid {
    grid-template-columns: 1fr 1fr;
  }
}

/* Below 520px — full single‑column */
@media (max-width: 520px) {
  .header-inner {
    flex-wrap: wrap;
    min-height: auto;
    padding-block: 0.75rem;
    gap: 0.5rem;
  }

  .nav {
    width: 100%;
    justify-content: flex-end;
    gap: 1rem;
    font-size: 0.78rem;
  }

  .hero-actions {
    flex-direction: column;
    align-items: center;
  }

  .btn-primary,
  .btn-secondary {
    width: 100%;
    max-width: 260px;
    text-align: center;
  }

  .metrics-grid {
    grid-template-columns: 1fr;
  }

  .features-grid {
    grid-template-columns: 1fr;
  }

  .footer-inner {
    flex-direction: column;
    gap: 1.25rem;
  }
}

/* Extremely narrow — 320px safe */
@media (max-width: 360px) {
  .nav {
    gap: 0.6rem;
    font-size: 0.7rem;
  }

  .logo-text {
    font-size: 0.95rem;
  }

  .hero-heading {
    font-size: 1.5rem;
  }
}

/* Wide — cap line length for readability */
@media (min-width: 1200px) {
  body {
    font-size: 1.05rem;
  }
}

