/* =============================================================
   MURMUR — TECH‑NOIR STYLESHEET
   Palette: #e4e4e0 (bg), #e8192a (accent), thin borders,
   wide letter‑spacing on headings.
   No frameworks. Responsive 320px → 1200px.
   ============================================================= */

/* ----- Custom Properties ----- */
:root {
  --color-bg: #e4e4e0;
  --color-surface: #dadad5;
  --color-card: #eeeeea;
  --color-text: #1a1a1a;
  --color-muted: #5c5c55;
  --color-accent: #e8192a;
  --color-accent-soft: rgba(232, 25, 42, 0.08);
  --color-border: #c4c4bc;
  --border-thin: 1px solid var(--color-border);

  --font-mono: 'SF Mono', 'Cascadia Code', 'Consolas', 'Courier New', monospace;
  --font-sans: 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif;

  --ls-heading: 0.05em;
  --ls-wide: 0.09em;
  --radius: 4px;

  --max-width: 1120px;
  --gutter: clamp(1rem, 4vw, 2.5rem);
}

/* ----- Global Reset ----- */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-sans);
  background-color: var(--color-bg);
  color: var(--color-text);
  line-height: 1.6;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

img,
svg {
  display: block;
  max-width: 100%;
}

a {
  color: inherit;
  text-decoration: none;
}

/* ----- Layout Utilities ----- */
.container {
  width: 100%;
  max-width: var(--max-width);
  margin-inline: auto;
  padding-inline: var(--gutter);
}

/* ----- HEADER ----- */
.site-header {
  border-bottom: var(--border-thin);
  position: sticky;
  top: 0;
  z-index: 100;
  background-color: var(--color-bg);
  backdrop-filter: blur(6px);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: 56px;
}

.logo {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-weight: 700;
  font-size: 1.1rem;
  letter-spacing: var(--ls-heading);
}

.nav {
  display: flex;
  align-items: center;
  gap: 1.5rem;
  font-size: 0.875rem;
  letter-spacing: var(--ls-heading);
  text-transform: lowercase;
}

.nav a:not(.nav-cta) {
  color: var(--color-muted);
  transition: color 0.15s;
}

.nav a:not(.nav-cta):hover {
  color: var(--color-text);
}

.nav-cta {
  border: var(--border-thin);
  padding: 0.35rem 0.9rem;
  border-radius: var(--radius);
  font-weight: 600;
  background: transparent;
  transition: background 0.2s, color 0.2s, border-color 0.2s;
}

.nav-cta:hover {
  background: var(--color-text);
  color: var(--color-bg);
  border-color: var(--color-text);
}

/* ----- HERO ----- */
.hero {
  padding: clamp(3rem, 8vw, 5.5rem) 0 clamp(2rem, 6vw, 4rem);
  text-align: center;
}

.hero-overline {
  display: inline-block;
  font-family: var(--font-mono);
  font-size: 0.7rem;
  letter-spacing: var(--ls-wide);
  text-transform: uppercase;
  color: var(--color-muted);
  border: var(--border-thin);
  padding: 0.25rem 0.75rem;
  border-radius: 99px;
  margin-bottom: 1.25rem;
}

.hero-heading {
  font-size: clamp(1.8rem, 5.5vw, 3.2rem);
  font-weight: 800;
  line-height: 1.12;
  letter-spacing: var(--ls-heading);
  max-width: 800px;
  margin: 0 auto 1rem;
}

.text-accent {
  color: var(--color-accent);
}

.hero-lead {
  font-size: clamp(1rem, 2.5vw, 1.15rem);
  color: var(--color-muted);
  max-width: 600px;
  margin: 0 auto 2rem;
  line-height: 1.55;
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  justify-content: center;
}

/* ----- Buttons ----- */
.btn-primary,
.btn-secondary {
  display: inline-block;
  padding: 0.65rem 1.5rem;
  font-size: 0.9rem;
  font-weight: 600;
  border-radius: var(--radius);
  letter-spacing: var(--ls-heading);
  transition: all 0.2s;
}

.btn-primary {
  background: var(--color-text);
  color: var(--color-bg);
  border: 1px solid var(--color-text);
}

.btn-primary:hover {
  background: var(--color-accent);
  border-color: var(--color-accent);
  color: #fff;
}

.btn-secondary {
  background: transparent;
  color: var(--color-text);
