  padding: var(--spacing-sm);
}

.metric-label {
  display: block;
  font-family: var(--font-mono);
  font-size: 0.85rem;
  font-weight: 600;
  letter-spacing: 0.06em;
  color: var(--accent);
  margin-bottom: 0.35rem;
}

.metric-value {
  display: block;
  font-family: var(--font-mono);
  font-size: clamp(2rem, 4vw, 2.8rem);
  font-weight: 800;
  letter-spacing: 0.04em;
  color: var(--text-on-dark);
  line-height: 1.1;
}

.metric-note {
  display: block;
  font-family: var(--font-sans);
  font-size: 0.75rem;
  color: var(--text-on-dark-muted);
  margin-top: 0.4rem;
  letter-spacing: 0.03em;
}

/* ----- Features Section ----- */
.features {
  padding: var(--spacing-xl) 0;
}

.section-heading {
  font-family: var(--font-mono);
  font-size: clamp(1.4rem, 3vw, 1.8rem);
  font-weight: 700;
  letter-spacing: 0.08em;
  text-align: center;
  text-transform: lowercase;
  margin-bottom: var(--spacing-lg);
  position: relative;
}

.section-heading::after {
  content: '';
  display: block;
  width: 50px;
  height: 2px;
  background-color: var(--accent);
  margin: var(--spacing-xs) auto 0;
}

.features-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: var(--spacing-md);
}

.feature-card {
  background-color: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-lg);
  padding: var(--spacing-md);
  transition: border-color 0.25s ease, box-shadow 0.25s ease,
    transform 0.2s ease;
}

.feature-card:hover {
  border-color: var(--accent);
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.06);
  transform: translateY(-2px);
}

.feature-icon {
  font-size: 1.6rem;
  color: var(--accent);
  margin-bottom: var(--spacing-sm);
  line-height: 1;
}

.feature-title {
  font-family: var(--font-mono);
  font-size: 1.1rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  margin-bottom: 0.6rem;
  color: var(--text);
}

.feature-body {
  font-size: 0.925rem;
  color: var(--text-secondary);
  line-height: 1.7;
}

/* ----- Testimonial ----- */
.testimonial {
  padding: var(--spacing-xl) 0;
  border-top: 1px solid var(--border);
}

.testimonial .section-heading {
  font-size: clamp(1rem, 2.5vw, 1.3rem);
  letter-spacing: 0.06em;
  color: var(--text-secondary);
  margin-bottom: var(--spacing-md);
}

.testimonial-quote {
  max-width: 700px;
  margin: 0 auto;
  text-align: center;
  position: relative;
}

.testimonial-quote > p {
  font-size: clamp(1.05rem, 2vw, 1.25rem);
  line-height: 1.75;
  color: var(--text);
  font-style: italic;
  letter-spacing: 0.02em;
}

.testimonial-quote > p::before {
  content: '\201C';
  font-family: var(--font-mono);
  font-size: 2.5rem;
  color: var(--accent);
  display: block;
  line-height: 1;
  margin-bottom: 0.3rem;
  font-style: normal;
}

.testimonial-attribution {
  margin-top: var(--spacing-md);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.2rem;
  font-style: normal;
}

.testimonial-author {
  font-weight: 700;
  font-style: normal;
  letter-spacing: 0.04em;
  color: var(--text);
  font-size: 0.95rem;
}

.testimonial-role {
  font-size: 0.8rem;
  color: var(--text-secondary);
  letter-spacing: 0.03em;
}

/* ----- Site Footer ----- */
.site-footer {
  background-color: var(--bg-dark);
  color: var(--text-on-dark);
  padding: var(--spacing-lg) 0 var(--spacing-md);
  margin-top: auto;
}

.footer-top {
  display: flex;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: var(--spacing-md);
  margin-bottom: var(--spacing-md);
}

.footer-brand {
  max-width: 280px;
}

.footer-logo {
  font-family: var(--font-mono);
  font-size: 1.2rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: lowercase;
  color: var(--text-on-dark);
}

.footer-tagline {
  font-size: 0.85rem;
  color: var(--text-on-dark-muted);
  margin-top: 0.4rem;
  letter-spacing: 0.03em;
}

.footer-nav {
  display: flex;
  gap: var(--spacing-lg);
  flex-wrap: wrap;
}

.footer-nav-group {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.footer-nav-group strong {
  font-family: var(--font-mono);
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-on-dark-muted);
  margin-bottom: 0.2rem;
}

.footer-nav-group a {
  font-size: 0.875rem;
  color: var(--text-on-dark);
  letter-spacing: 0.03em;
  transition: color 0.2s ease;
}

.footer-nav-group a:hover {
  color: var(--accent);
}

.footer-bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  padding-top: var(--spacing-sm);
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  font-size: 0.8rem;
  color: var(--text-on-dark-muted);
}

.footer-social {
  display: flex;
  gap: var(--spacing-sm);
}

.social-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border: 1px solid rgba(255, 255, 255, 0.2);
  border-radius: var(--radius);
  font-family: var(--font-mono);
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  color: var(--text-on-dark);
  transition: border-color 0.2s ease, color 0.2s ease,
    background-color 0.2s ease;
}

.social-link:hover {
  border-color: var(--accent);
  color: var(--accent);
  background-color: rgba(232, 25, 42, 0.1);
}

/* ----- Responsive: Mobile First (320px – 767px) ----- */
@media (max-width: 767px) {
  .site-header .container {
    flex-wrap: wrap;
    height: auto;
    padding-top: var(--spacing-xs);
    padding-bottom: var(--spacing-xs);
  }

  .site-nav {
    gap: var(--spacing-sm);
    flex-wrap: wrap;
    justify-content: center;
    margin-top: var(--spacing-xs);
  }

  .hero-headline {
    font-size: clamp(2.5rem, 10vw, 4rem);
  }

  .hero-actions {
    flex-direction: column;
    align-items: center;
  }

  .btn {
    width: 100%;
    max-width: 280px;
  }

  .metrics-grid {
    flex-direction: column;
    align-items: center;
  }

  .metric {
    max-width: 100%;
    width: 100%;
  }

  .footer-top {
    flex-direction: column;
  }

  .footer-nav {
    flex-direction: column;
    gap: var(--spacing-sm);
  }

  .footer-bottom {
    flex-direction: column;
    text-align: center;
  }
}

/* ----- Tablet & Small Desktop (768px – 1199px) ----- */
@media (min-width: 768px) {
  .features-grid {
    grid-template-columns: repeat(3, 1fr);
  }
}

/* ----- Large Desktop (≥1200px) ----- */
@media (min-width: 1200px) {
  .container {
    padding-left: 0;
    padding-right: 0;
  }
}

