/* styles.css */
:root {
  --bg: #e4e4e0;
  --accent: #e8192a;
  --text: #1a1a1a;
  --text-light: #4a4a4a;
  --border: #c4c4c0;
  --font-mono: 'Courier New', Courier, monospace;
  --font-sans: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen,
    Ubuntu, Cantarell, sans-serif;
}

*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  background-color: var(--bg);
  color: var(--text);
  font-family: var(--font-sans);
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

main {
  width: 100%;
  max-width: 70rem; /* 1120px – comfortable for 1200px screens */
  margin: 0 auto;
  padding: 2rem 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 4rem;
}

/* ---------- HERO ---------- */
.hero {
  text-align: center;
  padding-top: 3rem;
}

.hero h1 {
  font-size: clamp(2rem, 5vw, 3.5rem);
  font-weight: 700;
  line-height: 1.2;
  letter-spacing: 0.08em;
  color: var(--text);
}

.brand {
  color: var(--accent);
  font-weight: 800;
  letter-spacing: 0.12em;
}

.headline {
  font-weight: 500;
  letter-spacing: 0.04em;
}

.lead {
  margin-top: 1.5rem;
  font-size: 1.15rem;
  color: var(--text-light);
  max-width: 36rem;
  margin-left: auto;
  margin-right: auto;
}

.cta {
  display: inline-block;
  margin-top: 2rem;
  padding: 0.85rem 2rem;
  border: 1px solid var(--border);
  background: transparent;
  color: var(--accent);
  font-weight: 600;
  font-size: 0.95rem;
  text-decoration: none;
  letter-spacing: 0.05em;
  transition: background 0.15s ease, color 0.15s ease;
}

.cta:hover {
  background: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

/* ---------- FEATURE CARDS ---------- */
.features {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 2rem;
}

.feature-card {
  border: 1px solid var(--border);
  padding: 2rem 1.5rem;
  background: transparent;
  transition: border-color 0.15s;
}

.feature-card:hover {
  border-color: var(--accent);
}

.feature-card h2 {
  font-size: 1.35rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  margin-bottom: 0.75rem;
  color: var(--text);
}

.feature-card p {
  font-size: 0.95rem;
  color: var(--text-light);
  line-height: 1.6;
}

/* ---------- METRICS ---------- */
.metrics {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 2rem;
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  padding: 2.5rem 0;
  text-align: center;
}

.metric-item {
  flex: 1 1 150px;
  min-width: 120px;
}

.metric-value {
  display: block;
  font-family: var(--font-mono);
  font-size: clamp(2rem, 4vw, 2.8rem);
  font-weight: 700;
  letter-spacing: 0.05em;
  color: var(--accent);
  line-height: 1.1;
}

.metric-label {
  display: block;
  font-family: var(--font-mono);
  font-size: 0.9rem;
  letter-spacing: 0.1em;
  color: var(--text-light);
  margin-top: 0.35rem;
}

/* ---------- TESTIMONIAL ---------- */
.testimonial {
  max-width: 42rem;
  margin: 0 auto;
  padding: 2rem 1rem;
}

.testimonial blockquote {
  border-left: 3px solid var(--accent);
  padding-left: 1.8rem;
}

.testimonial p {
  font-size: 1.25rem;
  font-style: italic;
  line-height: 1.7;
  color: var(--text);
}

.testimonial cite {
  display: block;
  margin-top: 1rem;
  font-size: 0.95rem;
  font-style: normal;
  font-weight: 600;
  letter-spacing: 0.04em;
  color: var(--text-light);
}

/* ---------- FOOTER ---------- */
footer {
  text-align: center;
  font-size: 0.9rem;
  color: var(--text-light);
  padding-top: 2rem;
  border-top: 1px solid var(--border);
}

.social {
  display: flex;
  justify-content: center;
  gap: 1.5rem;
  margin: 1rem 0;
}

.social a {
  color: var(--text-light);
  text-decoration: none;
  letter-spacing: 0.05em;
  transition: color 0.15s;
}

.social a:hover {
  color: var(--accent);
}

.copyright {
  margin-top: 0.5rem;
  font-size: 0.8rem;
}

/* ---------- RESPONSIVE TWEAKS ---------- */
@media (max-width: 520px) {
  main {
    padding: 1.5rem 1rem;
    gap: 3rem;
  }

  .hero h1 {
    letter-spacing: 0.04em;
  }

  .features {
    grid-template-columns: 1fr;
  }

  .metrics {
    flex-direction: column;
    align-items: center;
    gap: 1.8rem;
  }

  .testimonial p {
    font-size: 1.1rem;
  }
}

/* ==========================================================================
   Murmur — Tech-Noir Stylesheet
   Palette: #e4e4e0 (bg), #e8192a (accent), #1a1a1a (text), thin borders
   ========================================================================== */

:root {
  --color-bg: #e4e4e0;
  --color-accent: #e8192a;
  --color-text: #1a1a1a;
  --color-text-light: #4a4a4a;
  --color-border: #c4c4c0;
  --color-white: #ffffff;

  --font-mono: 'SF Mono', 'Cascadia Code', 'Fira Code', 'Courier New', Courier, monospace;
  --font-sans: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen,
    Ubuntu, Cantarell, 'Helvetica Neue', sans-serif;

  --max-width: 68rem;
}

/* ---- Reset ---- */
*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  font-size: 100%;
  -webkit-text-size-adjust: 100%;
}

body {
  background-color: var(--color-bg);
  color: var(--color-text);
  font-family: var(--font-sans);
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* ---- Layout ---- */
main {
  width: 100%;
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 2.5rem 1.5rem 2rem;
  display: flex;
  flex-direction: column;
  gap: 4.5rem;
}

/* ---- Screen-reader only ---- */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* ==========================================================================
   HERO
   ========================================================================== */
.hero {
  text-align: center;
  padding-top: 3.5rem;
}

.hero h1 {
  font-size: clamp(1.8rem, 4.5vw, 3.4rem);
  font-weight: 700;
  line-height: 1.15;
  letter-spacing: 0.06em;
  color: var(--color-text);
  text-wrap: balance;
}

.brand {
  color: var(--color-accent);
  font-weight: 800;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.headline {
  font-weight: 500;
  letter-spacing: 0.03em;
}

.lead {
  margin-top: 1.5rem;
  font-size: clamp(1rem, 1.8vw, 1.2rem);
  color: var(--color-text-light);
  max-width: 38rem;
  margin-left: auto;
  margin-right: auto;
  text-wrap: balance;
}

.cta {
  display: inline-block;
  margin-top: 2rem;
  padding: 0.8rem 2.2rem;
  border: 1px solid var(--color-border);
  background: transparent;
  color: var(--color-accent);
  font-weight: 600;
  font-size: 0.95rem;
  text-decoration: none;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: background-color 0.18s ease, color 0.18s ease,
    border-color 0.18s ease;
}

.cta:hover,
.cta:focus-visible {
  background-color: var(--color-accent);
  color: var(--color-white);
  border-color: var(--color-accent);
  outline: none;
}

/* ==========================================================================
   FEATURE CARDS
   ========================================================================== */
.features {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 1.8rem;
}

.feature-card {
  border: 1px solid var(--color-border);
  padding: 2rem 1.6rem 1.8rem;
  background: transparent;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.feature-card:hover {
  border-color: var(--color-accent);
  box-shadow: 0 0 0 1px var(--color-accent);
}

.card-icon {
  font-size: 1.6rem;
  color: var(--color-accent);
  margin-bottom: 0.8rem;
  line-height: 1;
}

.feature-card h3 {
  font-size: 1.2rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  margin-bottom: 0.7rem;
  color: var(--color-text);
}

.feature-card p {
  font-size: 0.92rem;
  color: var(--color-text-light);
  line-height: 1.65;
}

/* ==========================================================================
   METRICS STRIP — id="metrics"
   ========================================================================== */
.metrics {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 2.5rem;
  border-top: 1px solid var(--color-border);
  border-bottom: 1px solid var(--color-border);
  padding: 3rem 1rem;
  text-align: center;
}

.metric-item {
  flex: 1 1 140px;
  min-width: 110px;
}

.metric-value {
  display: block;
  font-family: var(--font-mono);
  font-size: clamp(1.8rem, 3.5vw, 2.6rem);
  font-weight: 700;
  letter-spacing: 0.04em;
  color: var(--color-accent);
  line-height: 1.1;
}

.metric-label {
  display: block;
  font-family: var(--font-mono);
  font-size: 0.85rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--color-text-light);
  margin-top: 0.4rem;
}

/* ==========================================================================
   TESTIMONIAL
   ========================================================================== */
.testimonial {
  max-width: 42rem;
  margin: 0 auto;
  padding: 1.5rem 1rem;
}

.testimonial blockquote {
  border-left: 3px solid var(--color-accent);
  padding-left: 1.8rem;
}

.testimonial p {
  font-size: clamp(1.05rem, 2vw, 1.3rem);
  font-style: italic;
  line-height: 1.7;
  color: var(--color-text);
  text-wrap: balance;
}

.testimonial cite {
  display: block;
  margin-top: 1rem;
  font-size: 0.9rem;
  font-style: normal;
  font-weight: 600;
  letter-spacing: 0.05em;
  color: var(--color-text-light);
}

/* ==========================================================================
   FOOTER
   ========================================================================== */
footer {
  text-align: center;
  font-size: 0.88rem;
  color: var(--color-text-light);
  padding-top: 2.5rem;
  border-top: 1px solid var(--color-border);
}

.footer-brand {
  font-weight: 700;
  letter-spacing: 0.12em;
  color: var(--color-accent);
  font-size: 1rem;
  margin-bottom: 0.25rem;
}

.footer-tagline {
  margin-bottom: 1.2rem;
  font-size: 0.85rem;
}

.social {
  display: flex;
  justify-content: center;
  gap: 2rem;
  margin: 1rem 0;
  flex-wrap: wrap;
}

.social a {
  color: var(--color-text-light);
  text-decoration: none;
  letter-spacing: 0.06em;
  font-weight: 500;
  font-size: 0.9rem;
  transition: color 0.18s ease;
  padding: 0.2rem 0.4rem;
}

.social a:hover,
.social a:focus-visible {
  color: var(--color-accent);
  outline: none;
  text-decoration: underline;
  text-underline-offset: 3px;
}

.copyright {
  margin-top: 0.8rem;
  font-size: 0.78rem;
  letter-spacing: 0.03em;
}

/* ==========================================================================
   RESPONSIVE — down to 320px
   ========================================================================== */
@media (max-width: 720px) {
  main {
    padding: 2rem 1rem 1.5rem;
    gap: 3.5rem;
  }

  .hero {
    padding-top: 2rem;
  }

  .hero h1 {
    letter-spacing: 0.04em;
  }

  .features {
    grid-template-columns: 1fr;
    gap: 1.2rem;
  }

  .metrics {
    gap: 1.8rem;
    padding: 2rem 0.5rem;
  }
}

@media (max-width: 420px) {
  main {
    padding: 1.5rem 0.75rem 1rem;
    gap: 2.8rem;
  }

  .hero h1 {
    letter-spacing: 0.03em;
  }

  .brand {
    letter-spacing: 0.08em;
  }

  .metrics {
    flex-direction: column;
    align-items: center;
    gap: 1.5rem;
  }

  .metric-item {
    min-width: unset;
    flex: unset;
  }

  .social {
    gap: 1.2rem;
    flex-direction: column;
    align-items: center;
    gap: 0.6rem;
  }

  .testimonial blockquote {
    padding-left: 1.2rem;
  }
}

@media (max-width: 320px) {
  main {
    padding: 1rem 0.5rem 0.75rem;
    gap: 2.2rem;
  }

  .hero h1 {
    font-size: 1.5rem;
  }

  .feature-card {
    padding: 1.2rem 1rem;
  }

  .metrics {
    padding: 1.5rem 0.3rem;
  }
}

