*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-sans);
  line-height: 1.6;
  min-width: 320px;
}

/* ===== Typography ===== */
h1, h2, h3 {
  letter-spacing: 0.15em;
  font-weight: 700;
}

h1 {
  font-size: clamp(2rem, 5vw, 3.5rem);
  line-height: 1.2;
}

h2 {
  font-size: clamp(1.5rem, 4vw, 2.2rem);
  margin-bottom: 2rem;
  position: relative;
  display: inline-block;
}

h2::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: -6px;
  width: 40%;
  height: 2px;
  background: var(--accent);
}

h3 {
  font-size: 1.2rem;
  margin-bottom: 0.8rem;
  letter-spacing: 0.12em;
}

/* ===== Layout ===== */
.container {
  max-width: 1100px;
  margin: 0 auto;
  padding: 0 1.5rem;
}

/* ===== Header ===== */
header {
  border-bottom: 1px solid var(--border);
  padding: 1rem 0;
}

.header-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
}

.logo {
  font-weight: 700;
  font-size: 1.4rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--accent);
}

nav a {
  color: var(--text);
  text-decoration: none;
  margin-left: 2rem;
  font-size: 0.9rem;
  letter-spacing: 0.08em;
  transition: color 0.2s;
  border-bottom: 1px solid transparent;
  padding-bottom: 2px;
}

nav a:hover {
  color: var(--accent);
  border-bottom-color: var(--accent);
}

/* ===== Hero ===== */
.hero {
  padding: 5rem 0 4rem;
  text-align: center;
}

.hero-sub {
  font-size: 1.2rem;
  color: var(--muted);
  margin: 1rem 0 2rem;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
}

.cta {
  display: inline-block;
  background: var(--accent);
  color: #fff;
  text-decoration: none;
  padding: 0.85rem 2.5rem;
  border-radius: 4px;
  font-weight: 600;
  letter-spacing: 0.08em;
  transition: background 0.2s, transform 0.1s;
}

.cta:hover {
  background: #c41622;
  transform: translateY(-1px);
}

/* ===== Features ===== */
#features {
  padding: 4rem 0;
}

.cards {
  display: flex;
  gap: 2rem;
  flex-wrap: wrap;
  justify-content: center;
}

.card {
  flex: 1 1 250px;
  background: var(--card-bg);
  border: 1px solid var(--border);
  padding: 2rem;
  border-radius: 2px;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.card:hover {
  border-color: var(--accent);
  box-shadow: 0 4px 20px rgba(0,0,0,0.06);
}

.card-icon {
  font-size: 2.8rem;
  color: var(--accent);
  margin-bottom: 1.2rem;
  display: block;
}

/* ===== Metrics ===== */
#metrics {
  padding: 4rem 0;
  text-align: center;
}

.stats {
  display: flex;
  justify-content: center;
  gap: 4rem;
  flex-wrap: wrap;
  margin: 2rem 0 1.5rem;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.stat-label {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.18em;
  color: var(--muted);
  margin-bottom: 0.4rem;
}

.stat-value {
  font-family: var(--font-mono);
  font-size: 3rem;
  font-weight: 700;
  color: var(--text);
  line-height: 1.1;
  border-bottom: 2px solid var(--accent);
  padding-bottom: 0.2rem;
}

.metrics-note {
  color: var(--muted);
  font-size: 0.9rem;
}

/* ===== Testimonial ===== */
#testimonial {
  padding: 4rem 0;
}

blockquote {
  max-width: 700px;
  margin: 0 auto;
  padding: 2rem;
  border-left: 4px solid var(--accent);
  font-style: italic;
  font-size: 1.25rem;
  color: #2a2a2a;
  background: rgba(255,255,255,0.3);
  border-radius: 0 4px 4px 0;
}

blockquote p {
  margin-bottom: 1rem;
  line-height: 1.7;
}

cite {
  display: block;
  font-style: normal;
  font-weight: 600;
  color: var(--text);
  font-size: 1rem;
  letter-spacing: 0.05em;
}

/* ===== Footer ===== */
footer {
  border-top: 1px solid var(--border);
  padding: 2.5rem 0;
}

.footer-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 1rem;
}

.social-links {
  display: flex;
  gap: 1rem;
}

.social-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border: 1px solid var(--border);
  border-radius: 50%;
  font-family: var(--font-mono);
  font-weight: 700;
  font-size: 1.1rem;
  color: var(--text);
  text-decoration: none;
  transition: all 0.2s;
}

.social-icon:hover {
  border-color: var(--accent);
  color: var(--accent);
}

.copy {
  width: 100%;
  text-align: center;
  margin-top: 1.5rem;
  font-size: 0.85rem;
  color: var(--muted);
  letter-spacing: 0.04em;
}

/* ===== Responsive ===== */
@media (max-width: 768px) {
  .header-inner {
    flex-direction: column;
    gap: 0.5rem;
  }

  nav a {
    margin: 0 0.8rem;
  }

  .hero {
    padding: 3rem 0;
  }

  .cards {
    flex-direction: column;
    align-items: stretch;
  }

  .stats {
    gap: 2rem;
  }

  .stat-value {
    font-size: 2.2rem;
  }

  .footer-inner {
    flex-direction: column;
    text-align: center;
  }
}

@media (max-width: 480px) {
  h1 {
    font-size: 1.8rem;
  }

  .stat-value {
    font-size: 1.8rem;
  }

  blockquote {
    font-size: 1.1rem;
    padding: 1.5rem;
  }
}

