  font-size: 3rem;
  font-weight: 700;
  color: var(--text);
  line-height: 1.1;
  border-bottom: 2px solid var(--accent);
  padding-bottom: 0.2rem;
}

.metrics-note {
  color: var(--muted);
  font-size: 0.9rem;
}

/* ===== Testimonial ===== */
#testimonial {
  padding: 4rem 0;
}

blockquote {
  max-width: 700px;
  margin: 0 auto;
  padding: 2rem;
  border-left: 4px solid var(--accent);
  font-style: italic;
  font-size: 1.25rem;
  color: #2a2a2a;
  background: rgba(255,255,255,0.3);
  border-radius: 0 4px 4px 0;
}

blockquote p {
  margin-bottom: 1rem;
  line-height: 1.7;
}

cite {
  display: block;
  font-style: normal;
  font-weight: 600;
  color: var(--text);
  font-size: 1rem;
  letter-spacing: 0.05em;
}

/* ===== Footer ===== */
footer {
  border-top: 1px solid var(--border);
  padding: 2.5rem 0;
}

.footer-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 1rem;
}

.social-links {
  display: flex;
  gap: 1rem;
}

.social-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border: 1px solid var(--border);
  border-radius: 50%;
  font-family: var(--font-mono);
  font-weight: 700;
  font-size: 1.1rem;
  color: var(--text);
  text-decoration: none;
  transition: all 0.2s;
}

.social-icon:hover {
  border-color: var(--accent);
  color: var(--accent);
}

.copy {
  width: 100%;
  text-align: center;
  margin-top: 1.5rem;
  font-size: 0.85rem;
  color: var(--muted);
  letter-spacing: 0.04em;
}

/* ===== Responsive ===== */
@media (max-width: 768px) {
  .header-inner {
    flex-direction: column;
    gap: 0.5rem;
  }

  nav a {
    margin: 0 0.8rem;
  }

  .hero {
    padding: 3rem 0;
  }

  .cards {
    flex-direction: column;
    align-items: stretch;
  }

  .stats {
    gap: 2rem;
  }

  .stat-value {
    font-size: 2.2rem;
  }

  .footer-inner {
    flex-direction: column;
    text-align: center;
  }
}

@media (max-width: 480px) {
  h1 {
    font-size: 1.8rem;
  }

  .stat-value {
    font-size: 1.8rem;
  }

  blockquote {
    font-size: 1.1rem;
    padding: 1.5rem;
  }
}
